final:
module johnson_counter (
  input clk,
  input en,
  input rst,
  output reg [13:0] count);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        count <= 14'b00000000000000;
    else if (en)
        count <= {count[12:0], ~count[13]};
end
endmodule
